// Supertype unions (construction)
export type CompoundStatement =
  | ClassDefinition
  | DecoratedDefinition
  | ForStatement
  | FunctionDefinition
  | IfStatement
  | MatchStatement
  | TryStatement
  | WhileStatement
  | WithStatement
;

export type SimpleStatement =
  | AssertStatement
  | BreakStatement
  | ContinueStatement
  | DeleteStatement
  | ExecStatement
  | ExpressionStatement
  | FutureImportStatement
  | GlobalStatement
  | ImportFromStatement
  | ImportStatement
  | NonlocalStatement
  | PassStatement
  | PrintStatement
  | RaiseStatement
  | ReturnStatement
  | TypeAliasStatement
;

export type Expression =
  | AsPattern
  | BooleanOperator
  | ComparisonOperator
  | ConditionalExpression
  | Lambda
  | NamedExpression
  | NotOperator
;

export type Parameter =
  | DefaultParameter
  | DictionarySplatPattern
  | Identifier
  | KeywordSeparator
  | ListSplatPattern
  | PositionalSeparator
  | TuplePattern
  | TypedDefaultParameter
  | TypedParameter
;

export type Pattern =
  | Attribute
  | Identifier
  | ListPattern
  | ListSplatPattern
  | Subscript
  | TuplePattern
;

export type PrimaryExpression =
  | Attribute
  | Await
  | BinaryOperator
  | Call
  | ConcatenatedString
